package com.bionote.record;

import com.bionote.collaboration.EventService;
import com.bionote.attachment.AttachmentStorageService;
import com.bionote.common.ApiException;
import com.bionote.common.PagedResponse;
import com.bionote.template.TemplateService;
import com.fasterxml.jackson.core.type.TypeReference;
import com.fasterxml.jackson.databind.ObjectMapper;
import org.jsoup.Jsoup;
import org.jsoup.safety.Safelist;
import org.springframework.http.HttpStatus;
import org.springframework.jdbc.core.JdbcTemplate;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;
import java.sql.Timestamp;
import java.time.Instant;
import java.time.LocalDate;
import java.time.ZoneOffset;
import java.time.format.DateTimeFormatter;
import java.util.*;

@Service
public class RecordService {
    private final JdbcTemplate jdbc;private final ObjectMapper json;private final TemplateService templates;private final EventService events;private final AttachmentStorageService storage;
    public RecordService(JdbcTemplate jdbc,ObjectMapper json,TemplateService templates,EventService events,AttachmentStorageService storage){this.jdbc=jdbc;this.json=json;this.templates=templates;this.events=events;this.storage=storage;}
    private String encode(Object v){try{return json.writeValueAsString(v);}catch(Exception e){throw new IllegalArgumentException(e);}}
    private Object decode(String v){try{return json.readValue(v,Object.class);}catch(Exception e){return Map.of();}}
    private Map<String,Object> decodeMap(String v){try{return json.readValue(v,new TypeReference<>(){});}catch(Exception e){return new LinkedHashMap<>();}}

    @Transactional public RecordDtos.View create(UUID user,RecordDtos.CreateRequest request){String role=requireActiveProject(request.projectId(),user);if("REVIEWER".equals(role))throw new ApiException(HttpStatus.FORBIDDEN,"ACCESS_DENIED","审核者不能创建记录");Object snapshot=request.templateId()==null?Map.of("name","空白记录","version",1,"fields",List.of()):templates.get(user,request.templateId());Map<String,Object> defaults=new LinkedHashMap<>();if(snapshot instanceof com.bionote.template.TemplateDtos.View tv)for(var f:tv.fields())if(f.defaultValue()!=null)defaults.put(f.fieldKey(),f.defaultValue());UUID id=UUID.randomUUID();String code="EXP-"+DateTimeFormatter.BASIC_ISO_DATE.format(LocalDate.now(ZoneOffset.UTC))+"-"+id.toString().substring(0,8).toUpperCase(Locale.ROOT);Instant now=Instant.now();jdbc.update("INSERT INTO experiment_records(id,code,project_id,creator_id,title,experiment_type,experiment_date,purpose,status,template_snapshot_json,field_values_json,content_json,content_html_sanitized,content_plain_text,current_revision_no,version,created_at,updated_at) VALUES(?,?,?,?,?,?,?,?, 'IN_PROGRESS',?,?,?,?, '',0,0,?,?)",id.toString(),code,request.projectId().toString(),user.toString(),request.title().trim(),request.experimentType().trim(),request.experimentDate(),request.purpose().trim(),encode(snapshot),encode(defaults),"{}","",Timestamp.from(now),Timestamp.from(now));events.audit(user,request.projectId(),id,"RECORD_CREATED","RECORD",id,Map.of("title",request.title().trim(),"code",code));return get(user,id);}

    @Transactional public RecordDtos.View reserve(UUID user,RecordDtos.ReserveRequest request){
        String role=requireActiveProject(request.projectId(),user);if("REVIEWER".equals(role))throw new ApiException(HttpStatus.FORBIDDEN,"ACCESS_DENIED","审核者不能创建记录");
        Object snapshot=request.templateId()==null?Map.of("name","空白记录","version",1,"fields",List.of()):templates.get(user,request.templateId());
        Map<String,Object> defaults=new LinkedHashMap<>();String type="";
        if(snapshot instanceof com.bionote.template.TemplateDtos.View tv){type=Objects.toString(tv.experimentType(),"");for(var f:tv.fields())if(f.defaultValue()!=null)defaults.put(f.fieldKey(),f.defaultValue());}
        UUID id=UUID.randomUUID();String code="EXP-"+DateTimeFormatter.BASIC_ISO_DATE.format(LocalDate.now(ZoneOffset.UTC))+"-"+id.toString().substring(0,8).toUpperCase(Locale.ROOT);Instant now=Instant.now();
        jdbc.update("INSERT INTO experiment_records(id,code,project_id,creator_id,title,experiment_type,experiment_date,purpose,status,provisional,template_snapshot_json,field_values_json,content_json,content_html_sanitized,content_plain_text,current_revision_no,version,created_at,updated_at) VALUES(?,?,?,?,?,?,?,?, 'IN_PROGRESS',TRUE,?,?,?,?, '',0,0,?,?)",id.toString(),code,request.projectId().toString(),user.toString(),"未命名记录",type.isBlank()?"未分类":type,LocalDate.now(ZoneOffset.UTC),"",encode(snapshot),encode(defaults),"{}","",Timestamp.from(now),Timestamp.from(now));
        return get(user,id);
    }

    @Transactional public RecordDtos.View update(UUID user,UUID id,RecordDtos.UpdateRequest request){
        Map<String,Object> row=recordRow(id);UUID project=UUID.fromString(row.get("project_id").toString());requireMember(project,user);requireEditable(row,user);
        long currentVersion=((Number)row.get("version")).longValue();if(currentVersion!=request.version())throw new ApiException(HttpStatus.CONFLICT,"OPTIMISTIC_LOCK_CONFLICT","记录已被其他页面更新");
        validateFieldValues(row.get("template_snapshot_json").toString(),request.fieldValues());
        String title=request.title().trim(),type=request.experimentType().trim(),purpose=request.purpose().trim();
        String fields=encode(request.fieldValues()==null?Map.of():request.fieldValues()),content=encode(request.contentJson()==null?Map.of():request.contentJson());
        String clean=Jsoup.clean(request.contentHtml()==null?"":request.contentHtml(),Safelist.relaxed().addTags("h2","h3","blockquote","hr","pre","code","s","strike").addAttributes("a","target","rel"));String plain=Jsoup.parse(clean).text();
        boolean provisional=Boolean.TRUE.equals(row.get("provisional"));
        boolean same=title.equals(row.get("title"))&&type.equals(row.get("experiment_type"))&&request.experimentDate().equals(((java.sql.Date)row.get("experiment_date")).toLocalDate())&&purpose.equals(row.get("purpose"))&&fields.equals(row.get("field_values_json"))&&content.equals(row.get("content_json"))&&clean.equals(row.get("content_html_sanitized"));
        if(same&&!provisional)return get(user,id);
        int changed=jdbc.update("UPDATE experiment_records SET title=?,experiment_type=?,experiment_date=?,purpose=?,field_values_json=?,content_json=?,content_html_sanitized=?,content_plain_text=?,provisional=FALSE,updated_at=?,version=version+1 WHERE id=? AND version=? AND deleted_at IS NULL",title,type,request.experimentDate(),purpose,fields,content,clean,plain,Timestamp.from(Instant.now()),id.toString(),request.version());
        if(changed==0)throw new ApiException(HttpStatus.CONFLICT,"OPTIMISTIC_LOCK_CONFLICT","记录已被其他页面更新");
        events.audit(user,project,id,provisional?"RECORD_CREATED":"RECORD_UPDATED","RECORD",id,provisional?Map.of("title",title,"code",row.get("code")):Map.of("title",title));
        return get(user,id);
    }

    @Transactional public void discardReservation(UUID user,UUID id){Map<String,Object> row=recordRow(id);UUID project=UUID.fromString(row.get("project_id").toString());requireMember(project,user);if(!row.get("creator_id").toString().equals(user.toString()))throw new ApiException(HttpStatus.FORBIDDEN,"ACCESS_DENIED","只有记录创建者可以舍弃草稿");if(!Boolean.TRUE.equals(row.get("provisional")))throw new ApiException(HttpStatus.CONFLICT,"RECORD_STATE_CONFLICT","该记录已保存，不能按临时草稿舍弃");List<String> keys=jdbc.queryForList("SELECT storage_key FROM attachments WHERE record_id=?",String.class,id.toString());jdbc.update("DELETE FROM attachments WHERE record_id=?",id.toString());jdbc.update("DELETE FROM experiment_records WHERE id=? AND provisional=TRUE",id.toString());keys.forEach(storage::deleteQuietly);}

    public PagedResponse<RecordDtos.View> list(UUID user,UUID project,UUID creator,String status,String keyword,int page,int size){page=Math.max(0,page);size=Math.max(1,Math.min(100,size));String like="%"+esc(keyword)+"%";String where=" FROM experiment_records r JOIN project_members pm ON pm.project_id=r.project_id WHERE pm.user_id=? AND r.deleted_at IS NULL AND r.provisional=FALSE AND (? IS NULL OR r.project_id=?) AND (? IS NULL OR r.creator_id=?) AND (? IS NULL OR r.status=?) AND (LOWER(r.title) LIKE ? ESCAPE '!' OR LOWER(r.purpose) LIKE ? ESCAPE '!' OR LOWER(r.experiment_type) LIKE ? ESCAPE '!')";String p=project==null?null:project.toString(),c=creator==null?null:creator.toString(),st=status==null||status.isBlank()?null:status;long total=jdbc.queryForObject("SELECT COUNT(*)"+where,Long.class,user.toString(),p,p,c,c,st,st,like,like,like);List<RecordDtos.View> items=jdbc.query("SELECT r.id"+where+" ORDER BY r.updated_at DESC,r.id DESC LIMIT ? OFFSET ?",(rs,n)->get(user,UUID.fromString(rs.getString("id"))),user.toString(),p,p,c,c,st,st,like,like,like,size,page*size);return PagedResponse.of(items,page,size,total);}
    public RecordDtos.View get(UUID user,UUID id){Map<String,Object> r=recordRow(id);UUID project=UUID.fromString(r.get("project_id").toString());String role=requireMember(project,user);UUID creator=UUID.fromString(r.get("creator_id").toString());String projectName=jdbc.queryForObject("SELECT name FROM projects WHERE id=?",String.class,project.toString()),creatorName=jdbc.queryForObject("SELECT display_name FROM users WHERE id=?",String.class,creator.toString());boolean active="ACTIVE".equals(jdbc.queryForObject("SELECT status FROM projects WHERE id=?",String.class,project.toString())),editable=active&&creator.equals(user)&&Set.of("IN_PROGRESS","CHANGES_REQUESTED").contains(r.get("status")),provisional=Boolean.TRUE.equals(r.get("provisional"));String title=r.get("title").toString(),type=r.get("experiment_type").toString(),purpose=r.get("purpose").toString(),html=r.get("content_html_sanitized").toString(),plain=r.get("content_plain_text").toString();LocalDate date=((java.sql.Date)r.get("experiment_date")).toLocalDate();Object template=decode(r.get("template_snapshot_json").toString()),content=decode(r.get("content_json").toString()),displayed=null;Map<String,Object> values=decodeMap(r.get("field_values_json").toString());String revisionId="COMPLETED".equals(r.get("status"))?Objects.toString(r.get("final_revision_id"),null):"IN_REVIEW".equals(r.get("status"))&&r.get("current_review_id")!=null?jdbc.queryForObject("SELECT revision_id FROM reviews WHERE id=?",String.class,r.get("current_review_id")):null;if(revisionId!=null){Map<String,Object> rv=jdbc.queryForMap("SELECT revision_no,snapshot_json FROM record_revisions WHERE id=?",revisionId);Map<String,Object> snap=decodeMap(rv.get("snapshot_json").toString());title=Objects.toString(snap.get("title"),title);type=Objects.toString(snap.get("experimentType"),type);purpose=Objects.toString(snap.get("purpose"),purpose);date=LocalDate.parse(Objects.toString(snap.get("experimentDate"),date.toString()));template=snap.getOrDefault("templateSnapshot",template);values=snap.get("fieldValues") instanceof Map<?,?> m?new LinkedHashMap<>((Map<String,Object>)m):values;content=snap.getOrDefault("contentJson",content);html=Objects.toString(snap.get("contentHtml"),html);plain=Objects.toString(snap.get("contentPlainText"),plain);displayed=Map.of("id",revisionId,"revisionNo",((Number)rv.get("revision_no")).intValue());}return new RecordDtos.View(id,r.get("code").toString(),project,projectName,creator,creatorName,title,type,date,purpose,r.get("status").toString(),provisional,template,values,content,html,plain,((Number)r.get("current_revision_no")).intValue(),r.get("current_review_id")==null?null:UUID.fromString(r.get("current_review_id").toString()),displayed,((Number)r.get("version")).longValue(),((Timestamp)r.get("created_at")).toInstant(),((Timestamp)r.get("updated_at")).toInstant(),Map.of("canEdit",editable,"canDelete",editable&&!provisional,"canSubmit",editable&&!provisional,"canView",true,"isProjectOwner","OWNER".equals(role)));}
    @Transactional public void delete(UUID user,UUID id){Map<String,Object> r=recordRow(id);requireMember(UUID.fromString(r.get("project_id").toString()),user);requireEditable(r,user);jdbc.update("UPDATE experiment_records SET deleted_at=?,updated_at=?,version=version+1 WHERE id=?",Timestamp.from(Instant.now()),Timestamp.from(Instant.now()),id.toString());events.audit(user,UUID.fromString(r.get("project_id").toString()),id,"RECORD_DELETED","RECORD",id,Map.of("title",r.get("title")));}

    private void validateFieldValues(String snapshotJson,Map<String,Object> values){Object snapshot=decode(snapshotJson);if(!(snapshot instanceof Map<?,?> map))return;Object fieldObject=map.get("fields");if(!(fieldObject instanceof List<?> fields))return;Map<String,Object> safe=values==null?Map.of():values;for(Object o:fields){if(!(o instanceof Map<?,?> f))continue;String key=Objects.toString(f.get("fieldKey"),"");String type=Objects.toString(f.get("fieldType"),"");Object value=safe.get(key);if(value==null||value.toString().isBlank())continue;try{if("NUMBER".equals(type))Double.parseDouble(value.toString());if("DATE".equals(type))LocalDate.parse(value.toString());if("SELECT".equals(type)){Object opts=f.get("options");if(opts instanceof List<?> list&&!list.contains(value))throw new IllegalArgumentException();}if("FILE".equals(type)&&!(value instanceof List<?>||value instanceof String))throw new IllegalArgumentException();}catch(Exception e){throw new ApiException(HttpStatus.BAD_REQUEST,"VALIDATION_ERROR","模板字段值类型不正确",Map.of(key,"字段值类型不正确"));}}}
    private Map<String,Object> recordRow(UUID id){List<Map<String,Object>> rows=jdbc.queryForList("SELECT * FROM experiment_records WHERE id=? AND deleted_at IS NULL",id.toString());if(rows.isEmpty())throw new ApiException(HttpStatus.NOT_FOUND,"RESOURCE_NOT_FOUND","记录不存在");return rows.get(0);}
    private String requireMember(UUID project,UUID user){List<String> roles=jdbc.queryForList("SELECT pm.role FROM project_members pm JOIN projects p ON p.id=pm.project_id WHERE pm.project_id=? AND pm.user_id=?",String.class,project.toString(),user.toString());if(roles.isEmpty())throw new ApiException(HttpStatus.NOT_FOUND,"RESOURCE_NOT_FOUND","记录不存在或无权访问");return roles.get(0);}
    private String requireActiveProject(UUID project,UUID user){String role=requireMember(project,user);if(!"ACTIVE".equals(jdbc.queryForObject("SELECT status FROM projects WHERE id=?",String.class,project.toString())))throw new ApiException(HttpStatus.CONFLICT,"PROJECT_ARCHIVED","项目已归档，只能查看");return role;}
    private void requireEditable(Map<String,Object> row,UUID user){UUID project=UUID.fromString(row.get("project_id").toString());requireActiveProject(project,user);if(!row.get("creator_id").toString().equals(user.toString()))throw new ApiException(HttpStatus.FORBIDDEN,"ACCESS_DENIED","只有记录创建者可以编辑");if(!Set.of("IN_PROGRESS","CHANGES_REQUESTED").contains(row.get("status").toString()))throw new ApiException(HttpStatus.CONFLICT,"RECORD_STATE_CONFLICT","当前记录状态不可编辑");}
    private String esc(String v){return v==null?"":v.trim().toLowerCase(Locale.ROOT).replace("!","!!").replace("%","!%").replace("_","!_");}
}
